package com.restaurantcraft.block;
import com.restaurantcraft.blockentity.RestaurantManagementBlockEntity; import net.minecraft.core.*; import net.minecraft.network.chat.Component; import net.minecraft.server.level.ServerPlayer; import net.minecraft.world.*; import net.minecraft.world.entity.player.Player; import net.minecraft.world.level.*; import net.minecraft.world.level.block.*; import net.minecraft.world.level.block.entity.*; import net.minecraft.world.level.block.state.BlockState; import net.minecraft.world.phys.BlockHitResult; import org.jetbrains.annotations.Nullable;
public class RestaurantManagementBlock extends BaseEntityBlock { public RestaurantManagementBlock(Properties p){super(p);} public RenderShape getRenderShape(BlockState s){return RenderShape.MODEL;} @Nullable public BlockEntity newBlockEntity(BlockPos p, BlockState s){return new RestaurantManagementBlockEntity(p,s);} @Nullable public <T extends BlockEntity> BlockEntityTicker<T> getTicker(Level l, BlockState s, BlockEntityType<T> t){return l.isClientSide?null:(lvl,pos,st,be)->{if(be instanceof RestaurantManagementBlockEntity r)r.serverTick();};} public void setPlacedBy(Level l, BlockPos p, BlockState s, @Nullable net.minecraft.world.entity.LivingEntity e, net.minecraft.world.item.ItemStack st){ if(!l.isClientSide && e instanceof Player pl && l.getBlockEntity(p) instanceof RestaurantManagementBlockEntity be) be.bindOwner(pl); } public InteractionResult use(BlockState s, Level l, BlockPos p, Player player, InteractionHand h, BlockHitResult hit){ if(!l.isClientSide && l.getBlockEntity(p) instanceof RestaurantManagementBlockEntity be){ if(be.data.isOpen){player.displayClientMessage(Component.translatable("message.restaurant_craft.open_panel"),true); return InteractionResult.CONSUME;} if(player instanceof ServerPlayer sp) be.openMenu(sp); } return InteractionResult.sidedSuccess(l.isClientSide); } public void playerWillDestroy(Level l, BlockPos p, BlockState s, Player player){ if(!l.isClientSide && l.getBlockEntity(p) instanceof RestaurantManagementBlockEntity be && be.data.isOpen){ player.displayClientMessage(Component.translatable("message.restaurant_craft.cannot_break_open"),true); return;} super.playerWillDestroy(l,p,s,player);} }